import json
import re

# Get business data
file_path = None
if 'var_functions.query_db_20' in locals():
    if isinstance(var_functions.query_db_20, str) and var_functions.query_db_20.endswith('.json'):
        file_path = var_functions.query_db_20
        with open(file_path, 'r') as f:
            all_businesses = json.load(f)
    else:
        all_businesses = var_functions.query_db_20
else:
    all_businesses = var_functions.query_db_14

# Process businesses
category_counts = {}
category_business_refs = {}

for business in all_businesses:
    attributes = business.get('attributes', {})
    if isinstance(attributes, str) and attributes == 'None':
        continue

    if isinstance(attributes, dict):
        if attributes.get('BusinessAcceptsCreditCards') != 'True':
            continue
    else:
        continue

    description = business.get('description', '')
    business_id = business.get('business_id', '')
    business_ref = business_id.replace('businessid_', 'businessref_')

    categories = []

    # Pattern matching for categories
    patterns = [
        (r'in ([^.]+?)\.', ''),
        (r'including ([^.]+?)\.', ''),
        (r'services in ([^.]+?)\.', ''),
        (r'category of \'([^\']+)\'', '')
    ]

    for pattern, _ in patterns:
        match = re.search(pattern, description, re.IGNORECASE)
        if match:
            cat_text = match.group(1)
            cat_list = re.split(r',\s*|\sand\s', cat_text)
            for cat in cat_list:
                cat = cat.strip()
                if cat and len(cat) > 2:
                    categories.append(cat)
            break

    if not categories:
        if 'Salon' in description or 'Beauty' in description:
            categories = ['Beauty & Spas']
        elif 'Medical' in description or 'Doctor' in description:
            categories = ['Health & Medical']
        elif 'Restaurant' in description or 'Food' in description:
            categories = ['Restaurants']

    for category in categories:
        category_counts[category] = category_counts.get(category, 0) + 1
        if category not in category_business_refs:
            category_business_refs[category] = []
        category_business_refs[category].append(business_ref)

# Find top category
if category_counts:
    sorted_cats = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)
    top_category_name = sorted_cats[0][0]
    top_business_refs = category_business_refs[top_category_name]
    top_count = len(top_business_refs)
else:
    top_category_name = 'All Businesses'
    top_business_refs = []
    top_count = 0

result = {
    'top_category': top_category_name,
    'business_count': top_count,
    'business_refs': top_business_refs
}

print('__RESULT__:')
print(json.dumps(result))

