import json
import re

# Get all businesses accepting credit cards
businesses = var_functions.query_db_16

categories_data = {}

for biz in businesses:
    desc = biz.get('description', '')
    biz_id = biz.get('business_id', '')
    biz_ref = biz_id.replace('businessid_', 'businessref_')

    # Extract categories
    cats = []

    # Check for various patterns
    if 'in ' in desc:
        parts = desc.split(' in ')
        if len(parts) > 1:
            cat_part = parts[1].split('.')[0]
            cat_items = cat_part.split(',')
            for item in cat_items:
                item = item.strip().replace(' and ', ',')
                item_parts = item.split(',')
                for part in item_parts:
                    part_clean = part.strip().replace(',', '')
                    if part_clean and len(part_clean) > 2:
                        cats.append(part_clean)

    if not cats:
        if 'Beauty' in desc or 'Salon' in desc:
            cats = ['Beauty & Spas']
        elif 'Medical' in desc:
            cats = ['Health & Medical']
        elif 'Restaurant' in desc:
            cats = ['Restaurants']
        else:
            # General extraction
            if 'Education' in desc:
                cats.append('Education')
            if 'Shopping' in desc:
                cats.append('Shopping')
            if 'Beauty' in desc:
                cats.append('Beauty & Spas')

    for cat in cats:
        if cat not in categories_data:
            categories_data[cat] = []
        categories_data[cat].append(biz_ref)

# Find top category
top_category = max(categories_data.keys(), key=lambda k: len(categories_data[k]), default='None')
top_business_refs = categories_data.get(top_category, [])

result = {
    'top_category': top_category,
    'business_count': len(top_business_refs),
    'business_refs': top_business_refs
}

print('__RESULT__:')
print(json.dumps(result))

