    match = re.search(r'in ([^.]+?)\.', description)
    if match:
        cat_text = match.group(1)
        cat_parts = re.split(r',\s*| and | and ', cat_text)
        for part in cat_parts:
            part = part.strip()
            if part and part not in ['Local Services', 'Health & Medical', 'Shopping', 'Food', 'Beauty & Spas']:
                categories.append(part)

    # If no categories, classify based on keywords
    if not categories:
        if 'Beauty' in description or 'Salon' in description or 'Nail' in description:
            if 'Nail' in description:
                categories = ['Nail Salons']
            else:
                categories = ['Beauty & Spas']
        elif 'Medical' in description or 'Doctor' in description or 'Health' in description:
            categories = ['Health & Medical']
        elif 'Restaurant' in description or 'Food' in description:
            categories = ['Restaurants']
        elif 'Shopping' in description or 'Antique' in description:
            categories = ['Shopping']
        elif 'Education' in description or 'Preschool' in description or 'Montessori' in description:
            categories = ['Education']
        elif 'Gun' in description or 'Active Life' in description:
            categories = ['Active Life']
        elif 'Gun/Rifle Ranges' in description:
            categories = ['Active Life']
        else:
            # Generic category based on name
            if 'Salon' in name or 'Nails' in name:
                categories = ['Beauty & Spas']
            elif 'Medical' in name or 'Care' in name:
                categories = ['Health & Medical']
            elif 'Restaurant' in name or 'China' in name:
                categories = ['Restaurants']
            else:
                categories = ['Other']

    for category in categories:
        category_counts[category] = category_counts.get(category, 0) + 1
        if category not in business_refs_by_category:
            business_refs_by_category[category] = []
        business_refs_by_category[category].append(business_ref)

# Find the top category
if category_counts:
    top_category = max(category_counts, key=category_counts.get)
    top_business_refs = business_refs_by_category[top_category]
    top_count = category_counts[top_category]
else:
    top_category = 'Unknown'
    top_business_refs = []
    top_count = 0

result = {
    'top_category': top_category,
    'business_count': top_count,
    'business_refs': top_business_refs
}

print('__RESULT__:')
print(json.dumps(result))

