import json
import re

# Get the credit card businesses from query_db_16
cc_businesses = var_functions.query_db_16

# Build category dictionary
categories = {}

for biz in cc_businesses:
    desc = biz.get('description', '')
    name = biz.get('name', '')
    biz_id = biz.get('business_id', '')
    biz_ref = biz_id.replace('businessid_', 'businessref_')

    category_list = []

    # Try to extract categories from description
    # Look for "in Category1, Category2, and Category3." patterns
    match = re.search(r'in ([^.]+?)\.', desc)
    if match:
        cat_text = match.group(1)
        # Split by commas and "and"
        cat_items = cat_text.split(',')
        for item in cat_items:
            item = item.strip()
            if 'and ' in item:
                item = item.replace(' and ', ',')
                sub_items = item.split(',')
                for sub in sub_items:
                    sub = sub.strip()
                    if sub and sub not in ['a range of services']:
                        if sub not in ['Local Services', 'Health & Medical', 'Shopping', 'Food']:
                            category_list.append(sub)
            else:
                if item and item not in ['a range of services']:
                    if item not in ['Local Services', 'Health & Medical', 'Shopping', 'Food']:
                        category_list.append(item)

    # Classify by keywords if no pattern found
    if not category_list:
        if 'Salon' in desc or 'Beauty' in desc or 'Spa' in desc or 'Nails' in name:
            category_list.append('Beauty & Spas')
        elif 'Medical' in desc or 'Doctor' in desc or 'Health' in desc or 'Care' in name:
            category_list.append('Health & Medical')
        elif 'Restaurant' in desc or 'Food' in desc or 'China' in name:
            category_list.append('Restaurants')
        elif 'Gun' in desc or 'Active Life' in desc:
            category_list.append('Active Life')
        elif 'Montessori' in desc or 'Education' in desc:
            category_list.append('Education')
        elif 'Antique' in desc:
            category_list.append('Shopping')
        else:
            category_list.append('Other')

    # Count businesses per category
    for cat in category_list:
        cat = cat.strip()
        if cat:
            if cat not in categories:
                categories[cat] = []
            categories[cat].append(biz_ref)

# Find the category with most businesses
max_cat = max(categories.keys(), key=lambda k: len(categories[k]))
max_count = len(categories[max_cat])
max_business_refs = categories[max_cat]

result = {
    'top_category': max_cat,
    'business_count': max_count,
    'business_refs': max_business_refs
}

print('__RESULT__:')
print(json.dumps(result))

