import json
import re

# Get the credit card businesses
file_path = var_functions.query_db_34
with open(file_path, 'r') as f:
    cc_businesses = json.load(f)

# Categories tracking
category_businesses = {}
category_businesses_refs = {}

for business in cc_businesses:
    description = business.get('description', '')
    business_id = business.get('business_id', '')
    business_ref = business_id.replace('businessid_', 'businessref_')
    name = business.get('name', '')

    categories = []

    # Pattern 1: "in Category1, Category2, and Category3."
    match = re.search(r'in ([^.]+)\.', description)
    if match:
        cat_text = match.group(1)
        parts = re.split(r',\s*| and |&', cat_text)
        for part in parts:
            part = part.strip()
            if part and len(part) > 2:
                categories.append(part)

    # Pattern 2: "including Category1, Category2."
    if not categories:
        match = re.search(r'including ([^.]+)\.', description)
        if match:
            cat_text = match.group(1)
            parts = cat_text.split(',')
            for part in parts:
                part = part.strip()
                if part and len(part) > 2:
                    categories.append(part)

    # Pattern 3: "services in Category1, Category2."
    if not categories:
        match = re.search(r'services in ([^.]+)\.', description)
        if match:
            cat_text = match.group(1)
            parts = re.split(r',\s*| and ', cat_text)
            for part in parts:
                part = part.strip()
                if part and len(part) > 2:
                    categories.append(part)

    # If still no categories, use keyword classification
    if not categories:
        desc_lower = description.lower()
        name_lower = name.lower()

        if 'nails' in name_lower or 'salon' in name_lower or 'beauty' in desc_lower or 'spa' in desc_lower:
            categories = ['Beauty & Spa']
        elif 'restaurant' in name_lower or 'cafe' in name_lower or 'food' in desc_lower:
            categories = ['Restaurant']
        elif 'medical' in desc_lower or 'doctor' in desc_lower or 'health' in desc_lower or 'care' in name_lower:
            categories = ['Health & Medical']
        elif 'education' in desc_lower or 'preschool' in desc_lower or 'school' in name_lower:
            categories = ['Education']
        elif 'active life' in desc_lower or 'gun' in desc_lower or 'range' in name_lower:
            categories = ['Active Life']
        elif 'transportation' in desc_lower or 'taxi' in desc_lower or 'uber' in name_lower:
            categories = ['Transportation']
        elif 'shopping' in desc_lower or 'antique' in desc_lower or 'florist' in desc_lower:
            categories = ['Shopping']
        else:
            categories = ['Other']

    for category in categories:
        category = category.strip()
        if category:
            if category not in category_businesses:
                category_businesses[category] = 0
                category_businesses_refs[category] = []
            category_businesses[category] += 1
            category_businesses_refs[category].append(business_ref)

# Find top category
if category_businesses:
    top_category = max(category_businesses.keys(), key=lambda k: category_businesses[k])
    top_count = category_businesses[top_category]
    top_refs = category_businesses_refs[top_category]
else:
    top_category = 'Unknown'
    top_count = 0
    top_refs = []

result = {
    'top_category': top_category,
    'top_count': top_count,
    'top_business_refs': top_refs,
    'all_categories': category_businesses
}

print('__RESULT__:')
print(json.dumps(result))

