import json
import re

# Get credit card businesses data
file_path = var_functions.query_db_42
with open(file_path, 'r') as f:
    businesses = json.load(f)

print(f"Total businesses that accept credit cards: {len(businesses)}")

# Extract categories and count
category_businesses = {}
all_businesses_with_categories = []

for business in businesses:
    business_id = business.get('business_id', '')
    business_ref = business_id.replace('businessid_', 'businessref_')
    description = business.get('description', '')
    name = business.get('name', '')

    categories = []

    # Pattern 1: "in Category1, Category2, ..."
    match = re.search(r'in ([^.]+?)\.', description)
    if match:
        cat_text = match.group(1)
        # Remove common phrases
        cat_text = cat_text.replace(' the fields of ', '').replace(' a range of services ', '').replace(' a diverse ', '').replace(' a delightful ', '').replace(' a must-visit for anyone seeking ', '')
        cat_text = cat_text.replace(' this facility offers ', '').replace(' this establishment offers ', '').replace(' this business offers ', '').replace(' this charming establishment offers ', '')
        cat_text = cat_text.replace(' essential services in the categories of ', '')
        cat_text = cat_text.replace(' your home and decorative needs', '')
        cat_text = cat_text.replace(' your travel and transportation needs', '')

        # Split by commas or 'and'
        cat_parts = re.split(r',\s*| and ', cat_text)
        for part in cat_parts:
            part = part.strip()
            if part and len(part) > 2 and part not in ['Local Services', 'Health & Medical', 'Shopping', 'Food', 'a diverse selection', 'a delightful array', 'for all your home and decorative needs', 'to meet all your travel and transportation needs']:
                # Clean up individual parts
                part = part.replace(' the categories of ', '').replace(' the category of ', '').strip()
                if part.endswith(','):
                    part = part[:-1]
                if part and len(part) > 2:
                    categories.append(part)

    # Pattern 2: "including Category1, Category2"
    if not categories:
        match = re.search(r'including ([^.]+?)\.', description)
        if match:
            cat_text = match.group(1)
            cat_parts = re.split(r',\s*| and ', cat_text)
            for part in cat_parts:
                part = part.strip()
                if part and len(part) > 2:
                    categories.append(part)

    # Pattern 3: "category of 'Category'"
    if not categories:
        match = re.search(r"category of ['"]([^'"]+)['"]", description)
        if match:
            categories.append(match.group(1))

    # Classification fallback
    if not categories:
        desc_lower = description.lower()
        name_lower = name.lower()

        if 'nail' in name_lower or 'salon' in name_lower or 'spa' in name_lower:
            categories = ['Beauty & Spa']
        elif 'restaurant' in name_lower or 'cafe' in name_lower or 'china' in name_lower or 'wok' in name_lower:
            categories = ['Restaurant']
        elif 'gun' in name_lower or 'active life' in desc_lower:
            categories = ['Active Life']
        elif 'florist' in name_lower or 'floral' in name_lower:
            categories = ['Florist']
        elif 'medical' in name_lower or 'care' in name_lower:
            categories = ['Health & Medical']
        elif 'education' in desc_lower or 'preschool' in desc_lower or 'school' in name_lower:
            categories = ['Education']
        elif 'antique' in name_lower:
            categories = ['Antiques']
        elif 'transportation' in desc_lower or 'taxi' in desc_lower or 'uber' in name_lower:
            categories = ['Transportation']
        elif 'convenience store' in desc_lower:
            categories = ['Convenience Store']
        else:
            categories = ['Other']

    for category in categories:
        category = category.strip()
        if category:
            if category not in category_businesses:
                category_businesses[category] = []
            category_businesses[category].append({
                'business_ref': business_ref,
                'business_id': business_id
            })

# Find top category
category_counts = {cat: len(bus_list) for cat, bus_list in category_businesses.items()}
if category_counts:
    top_category = max(category_counts.keys(), key=lambda k: category_counts[k])
    top_count = category_counts[top_category]
    top_business_refs = [b['business_ref'] for b in category_businesses[top_category]]
else:
    top_category = 'Unknown'
    top_count = 0
    top_business_refs = []

result = {
    'top_category': top_category,
    'top_count': top_count,
    'top_business_refs': top_business_refs,
    'category_counts': category_counts,
    'total_businesses': len(businesses)
}

print('__RESULT__:')
print(json.dumps(result))

