import json
import re

# Load credit card businesses
cc_data = var_functions.query_db_86

print(f'Found {len(cc_data)} credit card businesses')

# Extract categories from descriptions
category_counts = {}
category_refs = {}

for biz in cc_data:
    desc = biz.get('description', '')
    biz_id = biz.get('business_id', '')
    biz_ref = biz_id.replace('businessid_', 'businessref_')

    # Initialize categories list
    categories = []

    # Pattern: find text after "in" until period
    match = re.search(r'in ([^.]+?)\.', desc)
    if match:
        categories_text = match.group(1)
        # Clean up common phrases
        categories_text = categories_text.replace(' the fields of ', '').replace(' a range of services ', '')
        categories_text = categories_text.replace(' a diverse range of services and products in the fields of ', '')

        # Split by comma or "and"
        cat_parts = re.split(r',\s*|\sand\s', categories_text)
        for part in cat_parts:
            part = part.strip()
            if part and len(part) > 2 and part not in ['Local Services', 'Health & Medical', 'Shopping', 'Food', 'Home & Garden']:
                # Further clean up each category
                if part.startswith('in '):
                    part = part[3:]
                categories.append(part)

    # If no categories found, do basic keyword classification
    if not categories:
        desc_lower = desc.lower()
        name_lower = biz.get('name', '').lower()

        if 'nail' in name_lower or 'salon' in name_lower or 'spa' in name_lower:
            categories = ['Beauty & Spa']
        elif 'restaurant' in name_lower or 'cafe' in name_lower or 'food' in desc_lower:
            categories = ['Restaurant']
        elif 'medical' in desc_lower or 'doctor' in desc_lower or 'health' in desc_lower:
            categories = ['Health & Medical']
        elif 'education' in desc_lower or 'preschool' in desc_lower or 'school' in name_lower:
            categories = ['Education']
        elif 'florist' in name_lower or 'floral' in name_lower:
            categories = ['Florist']
        elif 'transportation' in desc_lower or 'taxi' in desc_lower or 'uber' in name_lower:
            categories = ['Transportation']
        elif 'antique' in name_lower:
            categories = ['Antiques']
        elif 'convenience' in desc_lower:
            categories = ['Convenience Store']
        else:
            categories = ['Other']

    # Count businesses per category
    for cat in categories:
        cat_clean = cat.strip()
        if cat_clean:
            category_counts[cat_clean] = category_counts.get(cat_clean, 0) + 1
            if cat_clean not in category_refs:
                category_refs[cat_clean] = []
            category_refs[cat_clean].append(biz_ref)

# Find top category
if category_counts:
    top_category = max(category_counts.keys(), key=lambda k: category_counts[k])
    top_count = category_counts[top_category]
    top_business_refs = category_refs[top_category]
    print(f'Top category: {top_category} with {top_count} businesses')
else:
    top_category = 'Unknown'
    top_count = 0
    top_business_refs = []

print('Top categories:', sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:10])

result = {
    'top_category': top_category,
    'top_count': top_count,
    'top_business_refs': top_business_refs,
    'total_businesses': len(cc_data)
}

print(json.dumps(result))

