import json
import re

# Load all businesses from the query
businesses = var_functions.query_db_114

print(f'Total businesses loaded: {len(businesses)}')

# Extract categories and track business references
category_businesses = {}

for business in businesses:
    business_id = business.get('business_id', '')
    business_ref = business_id.replace('businessid_', 'businessref_')
    description = business.get('description', '')
    name = business.get('name', '')

    categories = []

    # Pattern 1: Find categories after "in"
    match = re.search(r'in ([^.]+?)\.', description)
    if match:
        cat_text = match.group(1)
        # Clean up the text
        cat_text = cat_text.replace(' the fields of ', '').replace(' a range of services ', '')
        # Split by commas and "and"
        cat_parts = re.split(r',\s*| and |&', cat_text)
        for part in cat_parts:
            part = part.strip()
            if part and len(part) > 2 and part not in ['Local Services', 'Health & Medical', 'Shopping', 'Food']:
                categories.append(part)

    # Pattern 2: Find categories after "including"
    if not categories:
        match = re.search(r'including ([^.]+?)\.', description)
        if match:
            cat_text = match.group(1)
            cat_parts = re.split(r',\s*| and ', cat_text)
            for part in cat_parts:
                part = part.strip()
                if part and len(part) > 2:
                    categories.append(part)

    # Pattern 3: Specific category formats
    if not categories:
        match = re.search(r"category of ['"]([^'"]+)['"]", description)
        if match:
            categories.append(match.group(1))

    # Keyword-based classification
    if not categories:
        desc_lower = description.lower()
        name_lower = name.lower()

        if any(word in name_lower for word in ['nail', 'salon', 'spa', 'beauty']):
            categories = ['Beauty & Spa']
        elif any(word in name_lower for word in ['restaurant', 'cafe', 'wok', 'china', 'mcdonald', 'subway']):
            categories = ['Restaurant']
        elif any(word in name_lower for word in ['gun', 'range']) or 'active life' in desc_lower:
            categories = ['Active Life']
        elif any(word in name_lower for word in ['medical', 'care', 'doctor', 'health']):
            categories = ['Health & Medical']
        elif any(word in desc_lower for word in ['preschool', 'education', 'school', 'montessori']):
            categories = ['Education']
        elif any(word in name_lower for word in ['florist', 'floral']):
            categories = ['Florist']
        elif any(word in desc_lower for word in ['transportation', 'taxi', 'uber']):
            categories = ['Transportation']
        elif any(word in name_lower for word in ['antique', 'gamestop', 'bloom', 'ross']):
            categories = ['Shopping']
        elif any(word in name_lower for word in ['convenience', 'market']):
            categories = ['Convenience Store']
        elif any(word in desc_lower for word in ['automotive', 'auto', 'car']):
            categories = ['Automotive']
        else:
            categories = ['Other']

    for category in categories:
        category = category.strip()
        if category:
            if category not in category_businesses:
                category_businesses[category] = []
            category_businesses[category].append(business_ref)

# Find top category
category_counts = {cat: len(refs) for cat, refs in category_businesses.items()}
if category_counts:
    top_category = max(category_counts.keys(), key=lambda k: category_counts[k])
    top_count = category_counts[top_category]
    top_business_refs = category_businesses[top_category]
else:
    top_category = 'Unknown'
    top_count = 0
    top_business_refs = []

print(f'Top category: {top_category} with {top_count} businesses')
print(f'Top 10 categories: {sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:10]}')

result = {
    'top_category': top_category,
    'business_count': top_count,
    'business_refs': top_business_refs,
    'all_categories': category_counts
}

print('__RESULT__:')
print(json.dumps(result))

